// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @dev Interfaccia minima del Coordinator (già definito nel tuo sistema).
interface ICoordinator {
    function notifyProof(uint256 requestId, bytes32 proofHash) external;
    function notifyError(uint256 requestId, string calldata reason) external;
}

/// @dev Interfaccia minima di uno smart contract Verifier.
/// @notice Può essere implementata come mock (ritorna sempre true)
///         o come vero verifier generato da snarkJS / altro sistema ZK.
interface IVerifier {
    function verify(bytes calldata proof, bytes32 infoHash) external view returns (bool);
}

/// @title ProofManager per zk-oracle prototype
/// @notice Gestisce lo storage delle prove e coordina con Verifier e Coordinator.
contract ProofManager {

    /// @notice Stato di una prova memorizzata.
    struct ProofRecord {
        bool exists;        // true se abbiamo una prova registrata per questo infoHash
        bytes32 infoHash;   // identificatore logico (es. hash dei parametri di conformità)
        bytes32 proofHash;  // hash della prova (es. keccak256(proof)
        bool isAggregate;   // true se si tratta di un'aggregazione di più prove
        uint64 timestamp;   // momento di memorizzazione (per analisi sperimentale)
    }

    /// @notice Admin del contratto (di solito il deployer).
    address public admin;

    /// @notice Indirizzo del Coordinator on-chain.
    address public coordinator;

    /// @notice Indirizzo dell'oracolo off-chain autorizzato a sottomettere prove.
    address public oracle;

    /// @notice Indirizzo del Verifier smart contract (opzionale).
    address public verifier;

    /// @dev Mapping infoHash -> prova
    mapping(bytes32 => ProofRecord) private proofs;

    /// @notice Emesso quando una prova viene memorizzata o aggiornata.
    event ProofStored(bytes32 indexed infoHash, bytes32 proofHash, bool isAggregate);

    /// @notice Emesso quando vengono modificati i riferimenti ai contratti esterni.
    event CoordinatorSet(address coordinator);
    event OracleSet(address oracle);
    event VerifierSet(address verifier);

    modifier onlyAdmin() {
        require(msg.sender == admin, "ProofManager: not admin");
        _;
    }

    modifier onlyOracle() {
        require(msg.sender == oracle, "ProofManager: not oracle");
        _;
    }

    constructor(address _admin) {
        require(_admin != address(0), "ProofManager: zero admin");
        admin = _admin;
    }

    // ============================================================
    //  CONFIGURAZIONE (da fare nel deployment script)
    // ============================================================

    /// @notice Imposta l'indirizzo del Coordinator.
    /// @dev Tipicamente chiamato dall'admin dopo il deploy di Coordinator.
    function setCoordinator(address _coordinator) external onlyAdmin {
        require(_coordinator != address(0), "ProofManager: zero coordinator");
        coordinator = _coordinator;
        emit CoordinatorSet(_coordinator);
    }

    /// @notice Imposta l'indirizzo dell'oracolo (off-chain agent).
    function setOracle(address _oracle) external onlyAdmin {
        require(_oracle != address(0), "ProofManager: zero oracle");
        oracle = _oracle;
        emit OracleSet(_oracle);
    }

    /// @notice Imposta l'indirizzo del Verifier smart contract.
    /// @dev Se non impostato (address(0)), la verifica on-chain viene saltata.
    function setVerifier(address _verifier) external onlyAdmin {
        verifier = _verifier;
        emit VerifierSet(_verifier);
    }

    // ============================================================
    //  API usata dal Coordinator (via interfaccia dichiarata in Coordinator.sol)
    // ============================================================

    /// @notice Restituisce se esiste già una prova per un certo infoHash,
    ///         usato dal Coordinator in modo sincrono quando arriva una nuova richiesta.
    /// @return exists true se abbiamo una prova, false altrimenti
    /// @return proofHash hash della prova (se exists == true)
    function getProofIfExists(bytes32 infoHash)
        external
        view
        returns (bool exists, bytes32 proofHash)
    {
        ProofRecord storage rec = proofs[infoHash];
        return (rec.exists, rec.proofHash);
    }

    // ============================================================
    //  API usata dall'oracolo (off-chain) per una richiesta specifica
    // ============================================================

    /// @notice Sottomette una prova per una richiesta specifica,
    ///         eventualmente verificandola tramite Verifier e notificando il Coordinator.
    ///
    /// @param requestId ID della richiesta (emesso dal Coordinator in VerificationRequested)
    /// @param infoHash identificatore logico della verifica (deve coincidere con quello del Coordinator)
    /// @param proof bytes della proof ZK (o altro formato proprietario)
    /// @param isAggregate true se la proof rappresenta un'aggregazione di più prove
    function submitProofForRequest(
        uint256 requestId,
        bytes32 infoHash,
        bytes calldata proof,
        bool isAggregate
    ) external onlyOracle {
        require(coordinator != address(0), "ProofManager: coordinator not set");

        // 1) Se è configurato un Verifier, verifichiamo on-chain la prova
        if (verifier != address(0)) {
            bool ok = IVerifier(verifier).verify(proof, infoHash);
            if (!ok) {
                ICoordinator(coordinator).notifyError(requestId, "Verification failed");
                return;
            }
        }

        // 2) Se esiste già una prova per questo infoHash, la riusiamo.
        ProofRecord storage rec = proofs[infoHash];
        bytes32 proofHashComputed;

        if (rec.exists) {
            // riuso di proofHash esistente
            proofHashComputed = rec.proofHash;
        } else {
            // primo inserimento per questo infoHash
            proofHashComputed = keccak256(proof);

            rec.exists = true;
            rec.infoHash = infoHash;
            rec.proofHash = proofHashComputed;
            rec.isAggregate = isAggregate;
            rec.timestamp = uint64(block.timestamp);

            emit ProofStored(infoHash, proofHashComputed, isAggregate);
        }

        // 3) Notifichiamo il Coordinator che la prova (nuova o esistente) e' disponibile
        ICoordinator(coordinator).notifyProof(requestId, proofHashComputed);
    }

    // ============================================================
    //  API di lettura per analisi sperimentale / client
    // ============================================================

    /// @notice Restituisce tutti i dettagli di una prova per un certo infoHash.
    function getProofRecord(bytes32 infoHash)
        external
        view
        returns (
            bool exists,
            bytes32 infoHashOut,
            bytes32 proofHash,
            bool isAggregate,
            uint64 timestamp
        )
    {
        ProofRecord storage rec = proofs[infoHash];
        return (rec.exists, rec.infoHash, rec.proofHash, rec.isAggregate, rec.timestamp);
    }
}
